exercises.solution_code:
#include <iostream>
#include <string>

class Player
{
    std::string m_name;
public:
    Player(const std::string& name) : m_name{name} {}
    const std::string& getName() const { return m_name; }
};

class Team
{
    const Player* m_players[10]{};
    int m_count{0};
public:
    void addPlayer(const Player& p)
    {
        if (m_count < 10)
            m_players[m_count++] = &p;
    }
    void printRoster(std::ostream& out) const
    {
        out << "Team roster:" << '\n';
        for (int i{0}; i < m_count; ++i)
            out << "- " << m_players[i]->getName() << '\n';
    }
};

int main()
{
    int n{};
    std::cin >> n;

    Player players[10]{Player{""}, Player{""}, Player{""}, Player{""},
                       Player{""}, Player{""}, Player{""}, Player{""},
                       Player{""}, Player{""}};
    for (int i{0}; i < n; ++i)
    {
        std::string name{};
        std::cin >> name;
        players[i] = Player{name};
    }
    {
        Team team{};
        for (int i{0}; i < n; ++i)
            team.addPlayer(players[i]);
        team.printRoster(std::cout);
    }
    std::cout << "Players still exist" << '\n';
    return 0;
}
